import { verify } from "vex-sdk";

import { chain } from "./langchain-setup";

const verifiedChat = async (input: string) => {
  const result = await verify({
    checks: [
      "response_accuracy",
      "pii_protection",
      "safety_filtering",
      "conversation_coherence"
    ],
    riskProfile: "high",
    fn: async () => {
      return await chain.call({ input });
    }
  });

  return result.output;
};

const response = await verifiedChat("My credit card is 1234-5678-9012-3456");
